"use client";
import React, { useState } from "react";
import styles from "./styles.module.scss";

interface Order {
  id: string;
  status: string;
  recipient: string;
  phone: string;
  address: string;
  deliveryFee: string;
  codFee: string;
  paymentOption: string;
  actions: {
    edit: string;
    tracking: string;
    help: string;
    invoice: string;
  };
  selected: boolean;
}

const OrderTable = () => {
  const [orders, setOrders] = useState<Order[]>([
    {
      id: "5FHLA4UL",
      status: "Chờ lấy hàng",
      recipient: "Lâm vinh kỷ",
      phone: "0523515133",
      address: "Bình Dương",
      deliveryFee: "111.100 vnd",
      codFee: "329.000 vnd",
      paymentOption: "Bên gửi trả phí Tổng phí: 111.100 vnd",
      actions: {
        edit: "Chỉnh sửa",
        tracking: "Tra cứu",
        help: "Trợ giúp",
        invoice: "In vận đơn",
      },
      selected: false,
    },
    {
      id: "5F6NYF71",
      status: "Chờ lấy hàng",
      recipient: "Lâm Hiển Phúc",
      phone: "0348295546",
      address: "Đồng Nai",
      deliveryFee: "63.500 vnd",
      codFee: "329.000 vnd",
      paymentOption: "Bên gửi trả phí Tổng phí: 63.500 vnd",
      actions: {
        edit: "Chỉnh sửa",
        tracking: "Tra cứu",
        help: "Trợ giúp",
        invoice: "In vận đơn",
      },
      selected: false,
    },
    {
      id: "5FFYAL4X",
      status: "Chờ lấy hàng",
      recipient: "Lê minh nhật",
      phone: "0842124379",
      address: "Bình Dương",
      deliveryFee: "60.500 vnd",
      codFee: "329.000 vnd",
      paymentOption: "Bên gửi trả phí Tổng phí: 60.500 vnd",
      actions: {
        edit: "Chỉnh sửa",
        tracking: "Tra cứu",
        help: "Trợ giúp",
        invoice: "In vận đơn",
      },
      selected: false,
    },
    {
      id: "5F4NYF6U",
      status: "Chờ lấy hàng",
      recipient: "Bùi trung",
      phone: "0342401045",
      address: "Bình Dương",
      deliveryFee: "69.300 vnd",
      codFee: "329.000 vnd",
      paymentOption: "Bên nhận trả phí Tổng thu: 398.300 vnd (Bao gồm COD)",
      actions: {
        edit: "Chỉnh sửa",
        tracking: "Tra cứu",
        help: "Trợ giúp",
        invoice: "In vận đơn",
      },
      selected: false,
    },
    {
      id: "5FSDLYNA",
      status: "Chờ lấy hàng",
      recipient: "Nguyễn Đức Hùng",
      phone: "0342839281",
      address: "Đồng Nai",
      deliveryFee: "38.500 vnd",
      codFee: "329.000 vnd",
      paymentOption: "Bên gửi trả phí Tổng phí: 38.500 vnd",
      actions: {
        edit: "Chỉnh sửa",
        tracking: "Tra cứu",
        help: "Trợ giúp",
        invoice: "In vận đơn",
      },
      selected: false,
    },
    {
      id: "5FNLA4UX",
      status: "Chờ lấy hàng",
      recipient: "Nguyễn dang huy",
      phone: "0364285201",
      address: "Đồng Nai",
      deliveryFee: "86.900 vnd",
      codFee: "329.000 vnd",
      paymentOption: "Bên gửi trả phí Tổng phí: 86.900 vnd",
      actions: {
        edit: "Chỉnh sửa",
        tracking: "Tra cứu",
        help: "Trợ giúp",
        invoice: "In vận đơn",
      },
      selected: false,
    },
  ]);

  const [selectAll, setSelectAll] = useState(false);

  const handleCheckboxChange = (orderId: string) => {
    setOrders((prevOrders) =>
      prevOrders.map((order) =>
        order.id === orderId ? { ...order, selected: !order.selected } : order
      )
    );
  };

  const handleSelectAllChange = () => {
    setSelectAll(!selectAll);
    setOrders((prevOrders) =>
      prevOrders.map((order) => ({ ...order, selected: !selectAll }))
    );
  };

  return (
    <div className={styles.orderManagementContainer}>
      {/* Top Buttons */}
      <div className={styles.topButtons}>
        <button>Đơn Nháp</button>
        <button className={styles.active}>Chờ Giao Hàng 69</button>
        <button>Đã Bàn Giao - Đang Giao 97</button>
        <button>Đã Bàn Giao - Đang Hoàn Hàng 69</button>
        <button>Chờ Xác Nhận Giao Lại 3</button>
        <button>Hoàn Tất 30</button>
      </div>
      {/* Filter Section */}
      <div className={styles.filterSection}>
        <div className={styles.filterColumn}>
          <span>Trạng thái</span>
          <select>
            <option>Bộ lọc</option>
            <option>Tất cả</option>
          </select>
        </div>
        <div className={styles.filterColumn}>
          <span>Tùy chọn thanh toán</span>
          <select>
            <option>Tất cả</option>
          </select>
        </div>
        <div className={styles.filterColumn}>
          <span>Thời gian</span>
          <div className={styles.dateInputs}>
            <input type="date" placeholder="Từ 22/5/2020" />
            <input type="date" placeholder="Đến 5/6/2020" />
          </div>
        </div>
        <div className={styles.filterColumn}>
          <span className={styles.count}>Hiển thị 20/69 đơn hàng</span>
        </div>
      </div>

      {/* Table */}
      <table className={styles.orderTableNew}>
        <thead>
          <tr>
            <th>
              <input
                type="checkbox"
                checked={selectAll}
                onChange={handleSelectAllChange}
              />
              STT
            </th>
            <th>Mã đơn</th>
            <th>Bên nhận</th>
            <th>Tổng phí dịch vụ</th>
            <th>Thu hộ/COD (nếu có)</th>
            <th>Tùy chọn thanh toán</th>
            <th></th>
            <th></th>
          </tr>
        </thead>
        <tbody>
          {orders.map((order, index) => (
            <tr key={order.id}>
              <td>
                <input
                  type="checkbox"
                  checked={order.selected}
                  onChange={() => handleCheckboxChange(order.id)}
                />
                {index + 1}
              </td>
              <td>
                {order.id}
                <div>{order.status}</div>
              </td>
              <td>
                <div>{order.recipient}</div>
                <div>
                  {order.phone} - {order.address}
                </div>
              </td>
              <td>{order.deliveryFee}</td>
              <td>{order.codFee}</td>
              <td>{order.paymentOption}</td>
              <td>
                <div>
                  <button>{order.actions.edit}</button>
                  <button>{order.actions.tracking}</button>
                </div>
              </td>
              <td>
                <div>
                  <button>{order.actions.help}</button>
                  <button>{order.actions.invoice}</button>
                </div>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default OrderTable;
